import{_ as a,o as i,c as o,ak as t}from"./chunks/framework.Bi-31Ycc.js";const y=JSON.parse('{"title":"Privacy Policy - WhatsZip Viewer","description":"","frontmatter":{"title":"Privacy Policy - WhatsZip Viewer"},"headers":[],"relativePath":"whatszip-viewer/privacy-policy.md","filePath":"whatszip-viewer/privacy-policy.md","lastUpdated":1772239018000}'),r={name:"whatszip-viewer/privacy-policy.md"};function n(s,e,l,c,h,d){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to “Privacy Policy”">​</a></h1><p>This Privacy Policy describes how WhatsZip Viewer (“the App”) collects, uses, and discloses your information in connection with your use of the App.</p><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h2><p>WhatsZip Viewer is designed to help you view and interact with WhatsApp chat exports (zip files) directly on your device. Our primary goal is to provide a secure and private viewing experience.</p><h2 id="information-we-do-not-collect" tabindex="-1">Information We DO NOT Collect <a class="header-anchor" href="#information-we-do-not-collect" aria-label="Permalink to “Information We DO NOT Collect”">​</a></h2><p><strong>WhatsZip Viewer is designed with your privacy in mind. We want to be absolutely clear: The App itself DOES NOT collect, store, transmit, or share any personal data from your device.</strong></p><p>This means:</p><ul><li>We do not collect your name, email address, phone number, or any other personally identifiable information.</li><li>We do not collect information about your device, location, or usage patterns.</li><li>We do not access or collect any data from the WhatsApp chat export files (including messages, images, videos, or audio) that you choose to load into the App. All processing of these files occurs <strong>locally on your device only</strong>.</li><li>We do not send any crash logs, analytics data, or usage statistics to our servers or third-party services.</li></ul><h2 id="how-we-handle-your-data-locally-on-your-device" tabindex="-1">How We Handle Your Data (Locally on Your Device) <a class="header-anchor" href="#how-we-handle-your-data-locally-on-your-device" aria-label="Permalink to “How We Handle Your Data (Locally on Your Device)”">​</a></h2><p>When you use WhatsZip Viewer, you interact with files (WhatsApp chat export zip files and their contents) that reside on your own device.</p><p><strong>Local Processing:</strong> The App functions entirely offline after installation. All parsing, displaying, and media playback of your chat data happens locally within the App on your device.</p><p><strong>Temporary Files:</strong> To facilitate viewing of media (images, videos, audio) within the App, temporary files may be created on your device. These temporary files are designed to be deleted automatically when the App is closed or when the associated media is no longer needed. We do not retain these temporary files beyond the immediate viewing session, and they are never transmitted off your device.</p><p><strong>No Cloud Storage Integration:</strong> WhatsZip Viewer does not integrate with any cloud storage services (e.g., Google Drive, iCloud, Dropbox) for uploading or storing your chat data. You are solely responsible for managing the storage and backup of your WhatsApp chat export files on your device.</p><h2 id="permissions-required-by-the-app" tabindex="-1">Permissions Required by the App <a class="header-anchor" href="#permissions-required-by-the-app" aria-label="Permalink to “Permissions Required by the App”">​</a></h2><p>WhatsZip Viewer requests the following permissions to function:</p><p><strong>Storage Access:</strong> This permission is required to allow you to select and load WhatsApp chat export zip files from your device’s storage, and to create temporary files for media playback. Without this permission, the App cannot open the chat export files.</p><h2 id="third-party-services" tabindex="-1">Third-Party Services <a class="header-anchor" href="#third-party-services" aria-label="Permalink to “Third-Party Services”">​</a></h2><p>WhatsZip Viewer does not integrate with any third-party analytics, advertising, or data collection services.</p><h2 id="children-s-privacy" tabindex="-1">Children’s Privacy <a class="header-anchor" href="#children-s-privacy" aria-label="Permalink to “Children’s Privacy”">​</a></h2><p>WhatsZip Viewer is not intended for use by children under the age of 13. We do not knowingly collect personal information from children under 13. If you believe we may have collected information from a child under 13, please contact us.</p><h2 id="changes-to-this-policy" tabindex="-1">Changes to This Policy <a class="header-anchor" href="#changes-to-this-policy" aria-label="Permalink to “Changes to This Policy”">​</a></h2><p>We may update our Privacy Policy from time to time. We will notify you of any changes by posting the new Privacy Policy on this page. You are advised to review this Privacy Policy periodically for any changes. Changes to this Privacy Policy are effective when they are posted on this page.</p><h2 id="contact-us" tabindex="-1">Contact Us <a class="header-anchor" href="#contact-us" aria-label="Permalink to “Contact Us”">​</a></h2><p>If you have any questions or suggestions about our Privacy Policy, please do not hesitate to contact us at:<br><a href="mailto:bxamra@icloud.com" target="_blank" rel="noreferrer">bxamra@icloud.com</a></p>',24)])])}const u=a(r,[["render",n]]);export{y as __pageData,u as default};
